"use client";
import { useCart } from '@/context/CartContext';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import SuccessOverlay from '@/components/SuccessOverlay';
import CheckoutProcessingModal from '@/components/CheckoutProcessingModal';
import MapLocationPicker from '@/components/MapLocationPicker';
import { calculateRoadDistance, calculateDeliveryFee, getCoordsForAddress } from '@/utils/logistics';

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5005';

export default function CheckoutPage() {
  const { cart, totalPrice, clearCart } = useCart();

  const [deliveryAddress, setDeliveryAddress] = useState('');
  const [landmark, setLandmark] = useState('');
  const [deliveryType, setDeliveryType] = useState<'asap' | 'scheduled'>('asap');
  const [scheduledTime, setScheduledTime] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [upiUTR, setUpiUTR] = useState('');
  const [upiScreenshot, setUpiScreenshot] = useState<string | null>(null);
  const [isElite, setIsElite] = useState(false);
  const [distance, setDistance] = useState(0);
  const [deliveryFee, setDeliveryFee] = useState(35);
  const [surge, setSurge] = useState({ isSurge: false, multiplier: 1 });
  const [isMapOpen, setIsMapOpen] = useState(false);
  const [isQrZoomed, setIsQrZoomed] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'COD' | 'UPI' | 'Card' | null>(null);

  useEffect(() => {
    const fetchSurge = async () => {
      try {
        const res = await fetch(`${API_URL}/api/orders/surge-status`);
        if (res.ok) {
          const data = await res.json();
          setSurge(data);
        }
      } catch (err) { console.error('Surge fetch failed', err); }
    };
    fetchSurge();
    const interval = setInterval(fetchSurge, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const initLocation = async () => {
      let currentAddress = '';

      // 1. Try local storage first for immediate UI
      try {
        const stored = localStorage.getItem('user');
        if (stored) {
          const parsed = JSON.parse(stored);
          setIsElite(parsed.isElite || false);
          if (parsed.address) {
            setDeliveryAddress(parsed.address);
            currentAddress = parsed.address;
          }
        }
      } catch { /* ignore */ }

      // 2. Fetch LATEST profile from server to ensure synchronization
      try {
        const token = localStorage.getItem('token');
        if (token) {
          const res = await fetch(`${API_URL}/api/users/profile`, {
            headers: { 'Authorization': `Bearer ${token}` }
          });
          if (res.ok) {
            const profile = await res.json();
            if (profile.address) {
              setDeliveryAddress(profile.address);
              currentAddress = profile.address;
              // Sync local storage
              const stored = localStorage.getItem('user');
              if (stored) {
                const parsed = JSON.parse(stored);
                localStorage.setItem('user', JSON.stringify({ ...parsed, ...profile }));
              }
            }
          }
        }
      } catch (err) { console.error('Profile sync failed', err); }

      // 3. ONLY auto-geolocate if we STILL don't have an address from profile
      if (!currentAddress && navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(async (pos) => {
          try {
            const { latitude, longitude } = pos.coords;
            const res = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1`, {
              headers: { 'Accept-Language': 'en' }
            });
            const data = await res.json();
            if (data.display_name) {
              setDeliveryAddress(data.display_name);
            }
          } catch (e) { console.error('Auto-location error:', e); }
        }, (err) => {
          console.warn('Geolocation access denied or failed.', err);
        });
      }
    };
    initLocation();
  }, []);

  // Dynamic fee calculation based on address
  useEffect(() => {
    if (!deliveryAddress) {
      setDeliveryFee(isElite ? 0 : 25);
      setDistance(0);
      return;
    }

    const restaurantCoords = getCoordsForAddress(cart[0]?.restaurantName || 'SRM');
    const customerCoords = getCoordsForAddress(deliveryAddress);

    const dist = calculateRoadDistance(
      restaurantCoords.lat, restaurantCoords.lon,
      customerCoords.lat, customerCoords.lon
    );

    setDistance(dist);
    setDeliveryFee(calculateDeliveryFee(dist, isElite, surge.multiplier));
  }, [deliveryAddress, isElite, cart, surge]);

  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [overlay, setOverlay] = useState<{ isOpen: boolean; title: string; message: string; type?: 'success' | 'error' }>({
    isOpen: false,
    title: '',
    message: '',
  });

  const finalTotal = totalPrice + deliveryFee;

  const handlePlaceOrder = async () => {
    if (!deliveryAddress.trim()) {
      setOverlay({ isOpen: true, title: 'Address Required', message: 'Please enter your delivery address.', type: 'error' });
      return;
    }

    if (!paymentMethod) {
      setOverlay({ isOpen: true, title: 'Payment Required', message: 'Please select a payment method.', type: 'error' });
      return;
    }

    if (paymentMethod === 'UPI' && (!upiUTR || !upiScreenshot)) {
      setOverlay({ isOpen: true, title: 'Payment Details Required', message: 'Please enter your UTR number and upload a transaction screenshot.', type: 'error' });
      return;
    }

    setCheckoutStatus('processing');
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setCheckoutStatus('error');
        setOverlay({ isOpen: true, title: 'Login Required', message: 'Please login to complete your order.', type: 'error' });
        setTimeout(() => window.location.href = '/login', 2000);
        return;
      }

      const orderData = {
        restaurantId: cart[0]?.restaurantId || '65f1a2b3c4d5e6f7a8b9c0d1',
        items: cart.map(item => ({
          menuItemId: item.id,
          name: item.name,
          quantity: item.quantity,
          priceAtOrder: item.price
        })),
        totalPrice,
        deliveryFee,
        distance,
        paymentMethod,
        upiUTR: paymentMethod === 'UPI' ? upiUTR : undefined,
        upiScreenshot: paymentMethod === 'UPI' ? upiScreenshot : undefined,
        deliverySlot: deliveryType === 'asap' ? 'ASAP' : scheduledTime,
        deliveryAddress: `${deliveryAddress}${landmark ? ', ' + landmark : ''}`,
        hostelGateDelivery: false
      };

      const response = await fetch(`${API_URL}/api/orders`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify(orderData)
      });

      if (response.ok) {
        const data = await response.json();
        setCheckoutStatus('success');
        clearCart();
        setTimeout(() => window.location.href = `/tracking?id=${data._id}`, 2000);
      } else {
        const err = await response.json();
        setCheckoutStatus('error');
        setErrorMsg(err.message || 'Payment Rejected by Node');
        setOverlay({ isOpen: true, title: 'Order Failed', message: err.message || 'Please try again.', type: 'error' });
      }
    } catch (error) {
      console.error('Checkout error:', error);
      setCheckoutStatus('error');
      setOverlay({ isOpen: true, title: 'Connection Issue', message: 'Could not connect to Zenvy servers.', type: 'error' });
    }
  };

  return (
    <main className="min-h-screen bg-background text-white p-6 pb-20">
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <Link href="/basket" className="w-10 h-10 bg-white/5 rounded-full flex items-center justify-center border border-white/10">
          <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" />
          </svg>
        </Link>
        <h1 className="text-xl font-black uppercase tracking-widest">Checkout</h1>
      </div>

      <div className="space-y-8">

        {/* Delivery Address */}
        <div>
          <h2 className="text-secondary-text font-black text-xs uppercase tracking-widest mb-4">Delivery Address</h2>
          <div className="space-y-3">
            <div className="relative flex items-center gap-2">
              <div className="relative flex-1">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-lg">≡ƒôì</span>
                <input
                  type="text"
                  value={deliveryAddress}
                  onChange={e => setDeliveryAddress(e.target.value)}
                  placeholder="Street, area, locality..."
                  className="w-full pl-12 pr-5 py-4 bg-white/5 border border-white/10 rounded-2xl text-white placeholder-gray-600 outline-none focus:border-primary-yellow/40 transition-all text-sm shadow-inner"
                />
              </div>
              <button
                onClick={() => setIsMapOpen(true)}
                className="h-[52px] px-4 bg-white/5 hover:bg-white/10 text-white border border-white/10 rounded-2xl flex items-center gap-3 transition-all group"
              >
                <img src="/assets/gmaps_icon.png" alt="Maps" className="w-6 h-6 object-contain group-hover:scale-110 transition-transform" />
                <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline-block">Live Map</span>
              </button>
            </div>
            <input
              type="text"
              value={landmark}
              onChange={e => setLandmark(e.target.value)}
              placeholder="Landmark (optional)"
              className="w-full px-5 py-4 bg-white/5 border border-white/10 rounded-2xl text-white placeholder-gray-600 outline-none focus:border-primary-yellow/40 transition-all text-sm"
            />
          </div>
        </div>

        {/* Delivery Time */}
        <div>
          <h2 className="text-secondary-text font-black text-xs uppercase tracking-widest mb-4">Delivery Time</h2>
          <div className="grid grid-cols-2 gap-3 mb-4">
            <button
              onClick={() => setDeliveryType('asap')}
              className={`p-5 rounded-[24px] border flex flex-col gap-1 transition-all ${deliveryType === 'asap' ? 'border-primary-yellow bg-primary-yellow/10' : 'border-white/10 bg-white/[0.02] hover:border-white/20'}`}
            >
              <span className="text-2xl">ΓÜí</span>
              <span className="text-sm font-black">ASAP</span>
              <span className="text-[10px] text-secondary-text font-bold">30ΓÇô50 mins</span>
            </button>
            <button
              onClick={() => setDeliveryType('scheduled')}
              className={`p-5 rounded-[24px] border flex flex-col gap-1 transition-all ${deliveryType === 'scheduled' ? 'border-primary-yellow bg-primary-yellow/10' : 'border-white/10 bg-white/[0.02] hover:border-white/20'}`}
            >
              <span className="text-2xl">≡ƒùô∩╕Å</span>
              <span className="text-sm font-black">Schedule</span>
              <span className="text-[10px] text-secondary-text font-bold">Pick a time</span>
            </button>
          </div>
          {deliveryType === 'scheduled' && (
            <input
              type="datetime-local"
              value={scheduledTime}
              onChange={e => setScheduledTime(e.target.value)}
              min={new Date(Date.now() + 30 * 60000).toISOString().slice(0, 16)}
              className="w-full px-5 py-4 bg-white/5 border border-white/10 rounded-2xl text-white outline-none focus:border-primary-yellow/40 transition-all text-sm"
            />
          )}
        </div>

        {/* Payment Method */}
        <div>
          <h2 className="text-secondary-text font-black text-xs uppercase tracking-widest mb-4">Payment Method</h2>
          <div className="grid grid-cols-3 gap-3">
            <button
              onClick={() => setPaymentMethod('COD')}
              className={`p-4 rounded-[24px] border flex flex-col items-center gap-2 transition-all ${paymentMethod === 'COD' ? 'border-primary-yellow bg-primary-yellow/10' : 'border-white/10 bg-white/[0.02] hover:border-white/20'}`}
            >
              <span className="text-xl">≡ƒÆ╡</span>
              <span className="text-[10px] font-black uppercase tracking-widest">Cash</span>
            </button>
            <button
              onClick={() => setPaymentMethod('UPI')}
              className={`p-4 rounded-[24px] border flex flex-col items-center gap-2 transition-all ${paymentMethod === 'UPI' ? 'border-primary-yellow bg-primary-yellow/10' : 'border-white/10 bg-white/[0.02] hover:border-white/20'}`}
            >
              <span className="text-xl">≡ƒô▓</span>
              <span className="text-[10px] font-black uppercase tracking-widest">UPI</span>
            </button>
            <button
              onClick={() => setPaymentMethod('Card')}
              className={`p-4 rounded-[24px] border flex flex-col items-center gap-2 transition-all ${paymentMethod === 'Card' ? 'border-primary-yellow bg-primary-yellow/10' : 'border-white/10 bg-white/[0.02] hover:border-white/20'}`}
            >
              <span className="text-xl">≡ƒÆ│</span>
              <span className="text-[10px] font-black uppercase tracking-widest">Card</span>
            </button>
          </div>

          {/* UPI Verification Section */}
          {paymentMethod === 'UPI' && (
            <div className="mt-6 p-6 bg-white/[0.03] border border-white/10 rounded-[32px] space-y-8 animate-in fade-in zoom-in duration-300">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="font-black uppercase tracking-widest text-sm text-primary-yellow">Instant UPI Gateway</h3>
                  <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest mt-1">Select your app to pay instantly</p>
                </div>
                <div className="w-10 h-10 bg-primary-yellow/10 rounded-xl flex items-center justify-center text-xl">≡ƒÆ│</div>
              </div>

              {/* App Buttons */}
              <div className="grid grid-cols-2 gap-4">
                <a
                  href={`upi://pay?pa=kesavakesava764@ybl&pn=ZenvyNexus&am=${finalTotal.toFixed(2)}&cu=INR`}
                  className="flex flex-col items-center gap-3 p-5 bg-[#5f259f]/10 border border-[#5f259f]/30 rounded-3xl hover:bg-[#5f259f]/20 transition-all group active:scale-95"
                >
                  <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform overflow-hidden">
                    <img src="/assets/phonepe_logo.png" alt="PhonePe" className="w-full h-full object-contain scale-110" />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-[#a882e0]">PhonePe</span>
                </a>

                <a
                  href={`upi://pay?pa=kesavakesava764@ybl&pn=ZenvyNexus&am=${finalTotal.toFixed(2)}&cu=INR`}
                  className="flex flex-col items-center gap-3 p-5 bg-white/5 border border-white/10 rounded-3xl hover:bg-white/10 transition-all group active:scale-95"
                >
                  <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform overflow-hidden">
                    <img 
                      src="/assets/gpay_logo.png" 
                      alt="GPay" 
                      className="w-full h-full object-contain scale-110" 
                      onError={(e) => {
                         const target = e.target as HTMLImageElement;
                         target.src = "https://www.gstatic.com/images/branding/product/2x/gpay_64dp.png";
                      }}
                    />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Google Pay</span>
                </a>
              </div>

              <div className="flex flex-col items-center gap-4">
                <div 
                  onClick={() => setIsQrZoomed(true)}
                  className="bg-white p-3 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.3)] group relative cursor-zoom-in active:scale-95 transition-all"
                >
                  <img 
                    src="/assets/upi_qr.png" 
                    alt="UPI QR Code" 
                    className="w-40 h-40 object-contain rounded-2xl"
                    onError={(e) => {
                      const target = e.target as HTMLImageElement;
                      target.src = "https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=upi://pay?pa=kesavakesava764@ybl&pn=ZenvyNexus&am=" + finalTotal;
                    }}
                  />
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      navigator.clipboard.writeText('kesavakesava764@ybl');
                      alert('UPI ID Copied!');
                    }}
                    className="absolute -bottom-2 translate-y-1/2 left-1/2 -translate-x-1/2 px-4 py-2 bg-[#C9A84C] text-black text-[10px] font-black uppercase tracking-widest rounded-full opacity-0 group-hover:opacity-100 transition-all shadow-2xl active:scale-90"
                  >
                    Copy ID
                  </button>
                </div>
                <div className="flex flex-col items-center gap-1">
                  <p className="text-[10px] font-black text-[#C9A84C] uppercase tracking-widest cursor-pointer hover:underline" onClick={() => {
                     navigator.clipboard.writeText('kesavakesava764@ybl');
                     alert('UPI ID Copied!');
                  }}>ID: kesavakesava764@ybl</p>
                  <p className="text-[8px] text-gray-500 font-bold uppercase tracking-widest">(Tap to Copy ID if buttons don't open app)</p>
                </div>
              </div>

              <div className="space-y-4 pt-4 border-t border-white/5">
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500 text-center">Post-Payment Verification</p>
                <input
                  type="text"
                  value={upiUTR}
                  onChange={(e) => setUpiUTR(e.target.value)}
                  placeholder="Paste 12-digit UTR Number"
                  className="w-full px-5 py-4 bg-white/5 border border-white/10 rounded-2xl text-white placeholder-gray-600 outline-none focus:border-primary-yellow/40 transition-all text-sm font-bold text-center"
                />

                <input
                  type="file"
                  accept="image/*"
                  onChange={async (e) => {
                    const file = e.target.files?.[0];
                    if (!file) return;
                    setIsUploading(true);
                    const formData = new FormData();
                    formData.append('image', file);
                    try {
                      const res = await fetch(`${API_URL}/api/upload`, { method: 'POST', body: formData });
                      const data = await res.json();
                      setUpiScreenshot(data.imageUrl);
                    } catch (err) { console.error('Upload failed', err); }
                    finally { setIsUploading(false); }
                  }}
                  className="hidden"
                  id="upi-upload"
                />
                <label 
                  htmlFor="upi-upload"
                  className="flex items-center justify-center w-full p-4 border border-white/10 rounded-2xl cursor-pointer hover:bg-white/5 transition-all gap-3 bg-white/[0.02]"
                >
                  {upiScreenshot ? (
                    <>
                       <span className="text-emerald-400 font-black text-xs uppercase tracking-widest">Γ£ô Receipt Attached</span>
                    </>
                  ) : isUploading ? (
                    <div className="animate-spin w-4 h-4 border-2 border-primary-yellow border-t-transparent rounded-full" />
                  ) : (
                    <>
                      <span className="text-xl">≡ƒô╕</span>
                      <span className="text-[10px] font-black uppercase tracking-widest text-secondary-text">Upload Screenshot</span>
                    </>
                  )}
                </label>
              </div>
            </div>
          )}
        </div>

        {/* Surge Warning */}
        {surge.isSurge && !isElite && (
          <div className="bg-primary-yellow/10 border border-primary-yellow/30 p-5 rounded-[24px] flex items-center gap-4 animate-pulse">
            <span className="text-2xl">≡ƒôê</span>
            <div>
              <p className="text-sm font-black text-primary-yellow">Surge Pricing Active</p>
              <p className="text-[10px] text-primary-yellow/80 font-bold">High demand in your area. Fees adjusted by {Math.round((surge.multiplier - 1) * 100)}%.</p>
            </div>
          </div>
        )}

        {/* Pricing Summary */}
        <div className="bg-card-bg p-7 rounded-[36px] border border-white/5 space-y-4">
          <div className="flex justify-between text-sm font-bold text-secondary-text">
            <span>Items Subtotal</span>
            <span>Γé╣{totalPrice}</span>
          </div>
          <div className="flex justify-between text-sm font-bold text-secondary-text">
            <span>Delivery Fee {distance > 0 ? `(${distance} km)` : ''}</span>
            {isElite ? (
              <span className="text-primary-yellow font-black">FREE (Elite)</span>
            ) : (
              <span>Γé╣{deliveryFee}</span>
            )}
          </div>
          <div className="border-t border-white/5 pt-4 flex justify-between items-center">
            <span className="text-xl font-black">To Pay</span>
            <span className="text-2xl font-black text-primary-yellow">Γé╣{finalTotal}</span>
          </div>
        </div>

        {/* CTA */}
        <button
          onClick={handlePlaceOrder}
          disabled={checkoutStatus === 'processing' || checkoutStatus === 'success'}
          className="w-full btn-yellow py-6 h-auto text-lg uppercase tracking-[0.2em] font-black shadow-[0_20px_60px_rgba(201,168,76,0.3)] disabled:opacity-30 transition-all premium-tilt animate-text-shimmer"
        >
          {checkoutStatus === 'processing' ? 'Processing Order...' : 'Confirm & Pay  ΓåÆ'}
        </button>
      </div>

      <SuccessOverlay
        isOpen={overlay.isOpen}
        onClose={() => setOverlay(prev => ({ ...prev, isOpen: false }))}
        title={overlay.title}
        message={overlay.message}
        type={overlay.type}
      />
      <CheckoutProcessingModal
        isOpen={checkoutStatus !== 'idle'}
        status={checkoutStatus as 'processing' | 'success' | 'error'}
        errorMessage={errorMsg}
      />

      <MapLocationPicker
        isOpen={isMapOpen}
        onClose={() => setIsMapOpen(false)}
        onConfirm={(address, coords) => {
          setDeliveryAddress(address);
        }}
      />

      {/* QR Zoom Overlay */}
      {isQrZoomed && (
        <div 
          className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-8 animate-in fade-in duration-300"
          onClick={() => setIsQrZoomed(false)}
        >
          <div className="relative max-w-sm w-full bg-white p-6 rounded-[40px] shadow-[0_0_80px_rgba(255,255,255,0.1)] scale-in-center overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-primary-yellow animate-shimmer" />
            <button className="absolute -top-12 right-0 text-white font-black uppercase tracking-widest text-[10px] flex items-center gap-2">
              Tap anywhere to close Γ£ò
            </button>
            <img 
              src="/assets/upi_qr.png" 
              alt="UPI QR Code" 
              className="w-full h-auto object-contain rounded-3xl"
              onError={(e) => {
                const target = e.target as HTMLImageElement;
                target.src = "https://api.qrserver.com/v1/create-qr-code/?size=400x400&data=upi://pay?pa=kesavakesava764@ybl&pn=ZenvyNexus&am=" + finalTotal;
              }}
            />
            <div className="mt-6 text-center">
              <p className="text-black font-black text-xs uppercase tracking-widest leading-loose">
                Scan to Pay Γé╣{finalTotal}<br/>
                <span className="text-gray-400">kesavakesava764@ybl</span>
              </p>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}

"use client";
import { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import Link from 'next/link';
import RestaurantCard from '@/components/RestaurantCard';
import { motion, AnimatePresence } from 'framer-motion';
import SafeImage from '@/components/SafeImage';
import ConciergeDrawer from '@/components/ConciergeDrawer';
import Image from 'next/image';
import SearchOverlay from '@/components/SearchOverlay';
import IntroOverlay from '@/components/IntroOverlay';
import ZenvyPulse from '@/components/ZenvyPulse';
import BlockWarsLeaderboard from '@/components/BlockWarsLeaderboard';
import ZenvyVault from '@/components/ZenvyVault';
import LiveOrderStatusBar from '@/components/LiveOrderStatusBar';
import ScrollProgressIndicator from '@/components/ScrollProgressIndicator';
import Magnetic from '@/components/Magnetic';
import { calculateRoadDistance } from '@/utils/logistics';
import RatingModal from '@/components/RatingModal';
import ZenvyModal from '@/components/ZenvyModal';
import Tilt from '@/components/Tilt';
import socket from '@/utils/socket';
import { Restaurant, User } from '@/types';
import RewardsPanel from '@/components/RewardsPanel';
import NexusLeaderboard from '@/components/NexusLeaderboard';
import { QRCodeSVG } from 'qrcode.react'; 

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5005';

function getGreeting(): string {
  const h = new Date().getHours();
  if (h < 12) return 'Good Morning';
  if (h < 17) return 'Good Afternoon';
  return 'Good Evening';
}

interface RentalItem {
  id?: string;
  name?: string;
  price?: number;
  imageUrl?: string;
  tags?: string[];
  restaurantName?: string;
  category?: string;
  specs?: { engine?: string; topSpeed?: string; power?: string; fuel?: string };
  ownerName?: string;
  ownerPhone?: string;
}

interface Order {
  _id: string;
  id?: string;
  status: string;
  totalPrice?: number;
  items?: { name: string; quantity: number; image?: string }[];
  restaurant?: string;
  restaurantId?: string;
  deliverySlot?: string;
  cancelSecondsLeft?: number;
}

export default function Home() {
  const [filter, setFilter] = useState<'all' | 'budget' | 'veg' | 'rating' | 'fastest' | 'premium'>('all');
  const [liveRestaurants, setLiveRestaurants] = useState<Restaurant[]>([]);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [userName, setUserName] = useState('');
  const [greeting, setGreeting] = useState('');
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<Array<{ id: number; title: string; message: string; time: string; type: 'promo' | 'info' | 'system' }>>([
    { id: 1, title: 'Welcome to Zenvy!', message: 'Explore the best gourmet picks in Amaravathi.', time: 'Just now', type: 'system' },
    { id: 2, title: 'Elite Membership', message: 'You are now a Verified Gourmet. Upgrade to Elite for free delivery!', time: '2h ago', type: 'promo' }
  ]);
  const [isAfter9, _setIsAfter9] = useState(false);
  const [showIntro, setShowIntro] = useState<boolean | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [isElite, setIsElite] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [activeCategory, setActiveCategory] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedRental, setSelectedRental] = useState<RentalItem | null>(null);
  const [showSpecs, setShowSpecs] = useState(false);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);
  const [cancelSecondsLeft, setCancelSecondsLeft] = useState(0);
  const [isRatingModalOpen, setIsRatingModalOpen] = useState(false);
  // favorites moved down for grouping
  const [sortBy, setSortBy] = useState<'default' | 'price-asc' | 'price-desc'>('default');
  const [favSort, setFavSort] = useState<'default' | 'price-asc' | 'price-desc' | 'name'>('default');
  const [restaurantSearch, setRestaurantSearch] = useState('');
  const [showConcierge, setShowConcierge] = useState(false);
  const gymMode = false;

  const [modalConfig, setModalConfig] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    type?: 'info' | 'success' | 'warning' | 'error';
    onConfirm?: () => void;
    confirmLabel?: string;
    cancelLabel?: string;
  }>({
    isOpen: false,
    title: '',
    message: '',
  });

  const showModal = (
    title: string, 
    message: string, 
    type: 'info' | 'success' | 'warning' | 'error' = 'info',
    onConfirm?: () => void,
    confirmLabel?: string,
    cancelLabel?: string
  ) => {
    setModalConfig({ isOpen: true, title, message, type, onConfirm, confirmLabel, cancelLabel });
  };

  const CITY_CATEGORIES = [
    { emoji: '≡ƒì¢', label: 'Biryani' },
    { emoji: '≡ƒìò', label: 'Pizza' },
    { emoji: '≡ƒÑù', label: 'South Indian' },
    { emoji: '≡ƒìö', label: 'Burgers' },
    { emoji: '≡ƒºü', label: 'Sweets' },
    { emoji: '≡ƒÑñ', label: 'Drinks' },
    { emoji: '≡ƒì£', label: 'Chinese' },
    { emoji: '≡ƒÑÖ', label: 'Rolls' },
    { emoji: '≡ƒìÄ', label: 'Fruits' },
    { emoji: '≡ƒÜ▓', label: 'Rental' },
    { emoji: '≡ƒÄü', label: 'Seasonal' },
    { emoji: '≡ƒÆ¬', label: 'Gym' },
    { emoji: '≡ƒæö', label: 'Laundry' },
    { emoji: '≡ƒÆè', label: 'Pharmacy' },
    { emoji: '≡ƒôÜ', label: 'Stationary' },
  ];

  useEffect(() => {
    setMounted(true);
    // Check if user has seen the cinematic intro this session
    const hasSeenIntro = sessionStorage.getItem('zenvy_intro_seen');
    setShowIntro(!hasSeenIntro);

    setGreeting(getGreeting());
    try {
      const stored = localStorage.getItem('user');
      if (stored) {
        const parsed = JSON.parse(stored);
        // Runtime Port Migration Guard: Patch legacy 5001 references in session
        if (parsed.profileImage && parsed.profileImage.includes(':5001')) {
          parsed.profileImage = parsed.profileImage.replace(':5001', ':5005');
          localStorage.setItem('user', JSON.stringify(parsed));
        }
        if (parsed.name) setUserName(parsed.name);
        setIsElite(parsed.isElite || false);
        setUser(parsed);
      }
      const storedFavs = localStorage.getItem('zenvy_favorites');
      if (storedFavs) setFavorites(JSON.parse(storedFavs));
    } catch { /* ignore */ }

    // Check backend mode and active orders
    const checkStatus = async () => {
      try {
        const token = localStorage.getItem('token');
        if (!token) return;

        await fetch(`${API_URL}/api/users/profile`, {
          headers: { Authorization: `Bearer ${token}` }
        });
      } catch (_err) {
        console.warn('[AUTH_CHECK] Background status check failed:', _err);
      }
    };

    checkStatus();

    // Asset Discovery Engine: Sync with Nexus Command Center
    const fetchLiveAssets = async () => {
      try {
        const res = await fetch(`${API_URL}/api/users/restaurants`);
        const data = await res.json();
        if (Array.isArray(data)) setLiveRestaurants(data);
      } catch (_err) {
        console.error('[ASSET_SYNC_ERROR]', _err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchLiveAssets();

    // Simulate finding an active order (for UX demo)
    const storedOrder = localStorage.getItem('last_order');
    if (storedOrder) {
      const parsed = JSON.parse(storedOrder);
      setActiveOrder(parsed);
      // Calculate remaining cancellation window (2 min = 120s)
      if (parsed.createdAt) {
        const elapsed = (Date.now() - new Date(parsed.createdAt).getTime()) / 1000;
        const remaining = Math.max(0, 120 - Math.round(elapsed));
        setCancelSecondsLeft(remaining);
      } else {
        setCancelSecondsLeft(120);
      }
    }

    // Simulate loading for UX polish


    return () => {

    };
  }, []);

  useEffect(() => {
    if (!user) return;
    const handleEliteUpdate = (data: { type: string; data: { userId: string; isElite: boolean } }) => {
      const userId = user?._id || user?.id;
      if (data.type === 'USER_ELITE_STATUS' && data.data.userId === userId) {
         setIsElite(data.data.isElite);
         const stored = localStorage.getItem('user');
         if (stored) {
           const parsed = JSON.parse(stored);
           parsed.isElite = data.data.isElite;
           localStorage.setItem('user', JSON.stringify(parsed));
         }
      }
    };
    socket.on('systemUpdate', handleEliteUpdate);
    return () => { socket.off('systemUpdate', handleEliteUpdate); };
  }, [user]);

  // Tick down cancellation countdown removed from Home to avoid global re-renders

  const cancelActiveOrder = async () => {
    if (cancelSecondsLeft <= 0) return;
    showModal(
      'Cancel Order?', 
      'Are you sure you want to cancel your current order? This action cannot be undone.',
      'warning',
      async () => {
        try {
          const token = localStorage.getItem('token');
          const orderId = activeOrder?._id || activeOrder?.id;
          if (orderId) {
            await fetch(`${API_URL}/api/orders/${orderId}/cancel`, {
              method: 'PUT',
              headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' }
            });
          }
        } catch (_err) {
          console.warn('[CANCEL_ORDER] Backend cancellation failed:', _err);
        }
        setActiveOrder(null);
        setCancelSecondsLeft(0);
        localStorage.removeItem('last_order');
      },
      'Yes, Cancel',
      'Keep Order'
    );
  };

  const handleRatingSubmit = async (rating: number, review: string) => {
    try {
      const token = localStorage.getItem('token');
      const orderId = activeOrder?._id || activeOrder?.id;
      if (!orderId) return;

      await fetch(`${API_URL}/api/orders/${orderId}/rate`, {
        method: 'PUT',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ rating, review })
      });

      // Update local wallet/points for UX
      if (user) {
        const updatedUser = { ...user, zenPoints: (user.zenPoints || 0) + 10 };
        setUser(updatedUser);
        localStorage.setItem('user', JSON.stringify(updatedUser));
      }
    } catch (_err) {
      console.error('[RATING_ERROR] Rating failed:', _err);
    }
  };

  const handleJoinElite = async () => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        alert('Please login to join Zenvy Elite!');
        return;
      }

      const res = await fetch(`${API_URL}/api/users/profile`, {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({ isElite: true })
      });
      const data = await res.json();
      if (res.ok) {
        setIsElite(true);
        setUser(data);
        localStorage.setItem('user', JSON.stringify(data));
        showModal('Welcome to Elite! ≡ƒÆÄ', 'You have successfully joined Zenvy Elite. Enjoy unlimited free delivery on all orders.', 'success');
      }
    } catch (_err) {
      console.error('[ELITE_ERROR] Failed to join elite:', _err);
    }
  };

  // Lock body scroll when rental modal is open
  useEffect(() => {
    if (selectedRental) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [selectedRental]);

  const handleIntroComplete = () => {
    sessionStorage.setItem('zenvy_intro_seen', 'true');
    setShowIntro(false);
  };

  const handlePrizeWin = (prize: { type: string; value: string | number }) => {
    if (prize.type === 'points') {
      const updatedUser = user ? { ...user, zenPoints: (user.zenPoints || 0) + (prize.value as number) } : null;
      if (updatedUser) {
        setUser(updatedUser);
        localStorage.setItem('user', JSON.stringify(updatedUser));
      }
      showModal(`Congratulations! ≡ƒÅå`, `You won ${prize.value} ZenPoints. Your new balance is ${updatedUser?.zenPoints || 0}.`, 'success');
    } else {
      showModal(`Exclusive Coupon! ≡ƒÅ╖∩╕Å`, `You've unlocked the code [${prize.value}]. It's been copied to your clipboard!`, 'success');
      navigator.clipboard.writeText(prize.value as string);
    }
  };

  const toggleFavorite = (id: string) => {
    setFavorites(prev => {
      const next = prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id];
      localStorage.setItem('zenvy_favorites', JSON.stringify(next));
      return next;
    });
  };

  // --- Smart Market Engine: Unified Tag-Based Catalog ---
  const allProducts = useMemo(() => {
    return liveRestaurants.flatMap(res => 
      (res.menu || []).map(item => ({ 
        ...item, 
        restaurantName: res.name, 
        restaurantId: res._id || res.id,
        isVegetarian: item.isVegetarian || item.tags?.includes('veg') || item.tags?.includes('fruits')
      }))
    ).filter(p => {
      // Apply Core Filters Globally
      if (filter === 'veg' && !p.isVegetarian) return false;
      if (filter === 'budget' && (p.price || 0) > 150) return false;
      if (filter === 'premium' && !p.isEliteOnly && (p.price || 0) < 500) return false; // Elite items or expensive ones
      if (gymMode && !p.tags?.includes('healthy') && !p.tags?.includes('high-protein')) return false;
      return true;
    }).sort((a, b) => {
      if (sortBy === 'price-asc') return (a.price || 0) - (b.price || 0);
      if (sortBy === 'price-desc') return (b.price || 0) - (a.price || 0);
      return 0;
    });
  }, [liveRestaurants, filter, gymMode, sortBy]);

  // Grouped Collections Driven by Tags (Now Respecting Global Filters)
  const groupedCollections = useMemo(() => {
    return {
      fruits: allProducts.filter(p => p.tags?.includes('fruits')),
      rentals: allProducts.filter(p => p.tags?.includes('rental')),
      sweets: allProducts.filter(p => p.tags?.includes('sweets')),
      seasonal: allProducts.filter(p => p.tags?.includes('seasonal')),
      drinks: allProducts.filter(p => p.tags?.includes('drinks')),
      gym: allProducts.filter(p => p.tags?.includes('gym') || p.tags?.includes('high-protein')),
      laundry: allProducts.filter(p => p.tags?.includes('laundry') || p.tags?.includes('dry-wash')),
      pharmacy: allProducts.filter(p => p.tags?.includes('medicine') || p.tags?.includes('pharmacy')),
      stationary: allProducts.filter(p => p.tags?.includes('stationary') || p.tags?.includes('books') || p.tags?.includes('print')),
      all: allProducts
    };
  }, [allProducts]);

  const favoriteItems = useMemo(() => {
    return allProducts
      .filter(p => favorites.includes(p.id!))
      .sort((a, b) => {
        if (favSort === 'price-asc') return (a.price || 0) - (b.price || 0);
        if (favSort === 'price-desc') return (b.price || 0) - (a.price || 0);
        if (favSort === 'name') return (a.name || '').localeCompare(b.name || '');
        return 0;
      });
  }, [allProducts, favorites, favSort]);

  const chefPicks = useMemo(() => groupedCollections.all.slice(0, 8), [groupedCollections.all]);

  const filteredByCategory = useMemo(() => {
    return allProducts
      .filter(p => {
        if (!activeCategory) return false;
        const cat = activeCategory.toLowerCase();
        const tags = Array.isArray(p.tags) ? p.tags : [];
        return (
          (p.category || '').toLowerCase().includes(cat) ||
          tags.some(t => t.toLowerCase().includes(cat)) ||
          (p.name || '').toLowerCase().includes(cat)
        );
      })
      .sort((a, b) => {
        if (sortBy === 'price-asc') return (a.price || 0) - (b.price || 0);
        if (sortBy === 'price-desc') return (b.price || 0) - (a.price || 0);
        return 0;
      });
  }, [allProducts, activeCategory, sortBy]);

  const displayRestaurants = useMemo(() => {
    return liveRestaurants.filter((res) => {
      if (gymMode && !res.tags?.includes('healthy') && !res.tags?.includes('gym')) {
         return (res.menu || []).some(item => item.tags?.includes('healthy') || item.tags?.includes('high-protein'));
      }
      const hasMenu = Array.isArray(res.menu) && res.menu.length > 0;

      // Core Category Filters
      if (filter === 'budget') return hasMenu && res.menu.some((item) => item.price < 150);
      if (filter === 'veg') return hasMenu && res.menu.some((item) => item.isVegetarian);
      if (filter === 'premium') return hasMenu && res.menu.some((item) => item.price > 500);

      // Advanced Discovery Filters
      const ratingNum = parseFloat(String(res.rating || "0"));
      if (filter === 'rating') return ratingNum >= 4.5;

      if (filter === 'fastest') {
        const timeStr = res.time || "40 min";
        const mins = parseInt(timeStr.split('-')[0]) || 40;
        if (mins > 35) return false;
      }

      // Local Item Search Filter
      if (restaurantSearch) {
        const query = restaurantSearch.toLowerCase();
        const matchesItem = (res.menu || []).some(item => 
          item.name.toLowerCase().includes(query) || 
          (item.category || '').toLowerCase().includes(query)
        );
        if (!matchesItem && !res.name.toLowerCase().includes(query)) return false;
      }

      return true;
    }).sort((a, b) => {
      // Apply global sorting to restaurants based on their best/cheapest item or rating
      if (sortBy === 'price-asc') {
         const aMin = Math.min(...(a.menu || []).map(i => i.price), 9999);
         const bMin = Math.min(...(b.menu || []).map(i => i.price), 9999);
         return aMin - bMin;
      }
      if (sortBy === 'price-desc') {
         const aMax = Math.max(...(a.menu || []).map(i => i.price), 0);
         const bMax = Math.max(...(b.menu || []).map(i => i.price), 0);
         return bMax - aMax;
      }
      return 0;
    }).map(res => {
      // Pre-calculate distance-based time once per data change
      let calculatedTime = res.time || "30-50 min";
      if (user?.defaultAddress) {
        const rCoords = { lat: res.lat || 16.4632, lon: res.lon || 80.5064 };
        const uCoords = { lat: 16.5062, lon: 80.6480 }; 
        const d = calculateRoadDistance(rCoords.lat, rCoords.lon, uCoords.lat, uCoords.lon);
        const mins = Math.round(d * 3 + 12);
        calculatedTime = `${mins}-${mins+10} min`;
      }
      return { ...res, calculatedTime };
    });
  }, [liveRestaurants, filter, gymMode, restaurantSearch, sortBy, user?.defaultAddress]);

  if (showIntro === null) return <div className="min-h-screen bg-black" />;

  return (
    <>
    <ScrollProgressIndicator />
    <main className={`min-h-screen text-white pb-32 relative overflow-hidden transition-colors duration-1000 ${isAfter9 ? 'bg-[#050507]' : 'bg-background'}`}>
      {showIntro && <IntroOverlay onComplete={handleIntroComplete} />}

      {/* Container for main content - only visible when intro is DONE */}
      <div className={`min-h-screen transition-opacity duration-1000 ${showIntro === false ? 'opacity-100' : 'opacity-0'} ${isAfter9 ? 'midnight-portal' : ''}`}>

        {/* Ambient Background Orbs (Lunar Shift - Unified Gold) */}
        <div className="fixed inset-0 pointer-events-none z-0">
          <div className={`absolute -top-40 -right-40 w-96 h-96 rounded-full blur-[120px] transition-colors duration-1000 ${isAfter9 ? 'bg-[#C9A84C]/[0.06]' : 'bg-[#C9A84C]/[0.04]'}`} />
          <div className={`absolute top-1/3 -left-32 w-80 h-80 rounded-full blur-[100px] transition-colors duration-1000 ${isAfter9 ? 'bg-[#C9A84C]/[0.05]' : 'bg-[#C9A84C]/[0.03]'}`} />
        </div>

        {/* Layout Grid: Content + Sidebar */}
        <div className="max-w-[1500px] mx-auto grid grid-cols-1 lg:grid-cols-[1fr_360px] gap-8 relative z-10">

          {/* Main Feed Content */}
          <div className="w-full px-6 pt-14 md:px-10 lg:px-14">
          {/* City Brand Header */}
          <motion.header 
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, ease: "easeOut" }}
            className="mb-6"
          >
            <div className="flex items-center justify-between mb-6">
              <Link href="/profile" className="flex items-center gap-2.5 group cursor-pointer">
                <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-[#C9A84C] to-[#8B7332] flex items-center justify-center shadow-lg shadow-[#C9A84C]/20 group-hover:scale-105 transition-transform overflow-hidden relative">
                  {user?.profileImage ? (
                    <img 
                      src={user.profileImage} 
                      alt="Me" 
                      className="w-full h-full object-cover" 
                      onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        const fallback = document.createElement('span');
                        fallback.className = "text-[13px] font-black text-black";
                        fallback.innerText = 'Z';
                        e.currentTarget.parentNode?.appendChild(fallback);
                      }}
                    />
                  ) : (
                    <span className="text-[13px] font-black text-black">Z</span>
                  )}
                </div>
                <div>
                  <span className="text-[11px] font-black uppercase tracking-[0.3em] text-gold-gradient block leading-none">Zenvy</span>
                  <span className="text-[7px] font-bold uppercase tracking-[0.4em] text-secondary-text block mt-0.5">Amaravathi, AP ≡ƒôì</span>
                </div>
              </Link>
              <div className="flex items-center gap-3">

                <Magnetic>
                  <button onClick={() => setShowNotifications(true)} className="w-10 h-10 glass-card rounded-full flex items-center justify-center relative group overflow-hidden">
                    <div className="absolute inset-0 bg-[#C9A84C]/0 group-hover:bg-[#C9A84C]/10 transition-colors" />
                    <svg className="w-4 h-4 text-secondary-text group-hover:text-[#C9A84C] transition-colors relative z-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                    </svg>
                    {notifications.length > 0 && <span className="absolute top-2.5 right-2.5 w-1.5 h-1.5 bg-primary-yellow rounded-full shadow-[0_0_8px_rgba(201,168,76,0.8)]" />}
                  </button>
                </Magnetic>
              </div>
            </div>
            <div className="flex justify-between items-end mb-2">
              <div className="flex flex-col">
                <div className="flex items-center gap-1.5 mb-1">
                  <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-secondary-text">
                    {mounted ? getGreeting() : 'Welcome'}
                    {mounted && userName ? `, ${userName.split(' ')[0]}` : ''}
                  </p>
                  {mounted && isElite && (
                    <span className="bg-[#C9A84C]/10 text-[#C9A84C] text-[8px] font-black px-2 py-0.5 rounded-full border border-[#C9A84C]/20 tracking-tighter shadow-[0_0_10px_rgba(201,168,76,0.1)]">ELITE</span>
                  )}
                </div>
              </div>
              <p className="text-[9px] font-black text-emerald-400 uppercase tracking-widest bg-emerald-500/10 px-3 py-1.5 rounded-full">Live Delivery Γ£ô</p>
            </div>
            <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-6">
               <div>
                  <h1 className={`text-4xl font-extrabold text-white italic leading-tight tracking-tighter ${isAfter9 ? 'midnight-glow-text' : ''}`} style={{ fontFamily: "'Syne', sans-serif" }}>
                    {isAfter9 ? 'MIDNIGHT NEXUS' : "LET'S CLEAR YOUR CRAVING"} 
                  </h1>
               </div>

              {/* ≡ƒÄü Minimalist Rewards Toolbar (Integrated Header Space) */}
              <div className="mb-2 md:mb-4">
                <RewardsPanel onWin={handlePrizeWin} />
              </div>
            </div>
            <div className="mt-4 flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-emerald-500 status-pulse shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
              <span className="text-[8px] font-black text-secondary-text uppercase tracking-widest opacity-60">Delivering across Amaravathi</span>
            </div>
          </motion.header>

          {/* User Requested Top Navigation Replica */}
          <nav className="flex items-center justify-around px-4 py-4 mb-6 bg-[#141416] border border-white/5 rounded-3xl z-40 relative shadow-2xl">
            <Link href="/" className="flex flex-col items-center gap-1.5 nav-icon-active">
              <div className="tab-pill">
