          <div className="mt-2">
            {children}
          </div>
        </motion.div>
      </div>,
      document.body
    );
  };

  return (
    <div className="flex items-center gap-3">
      {/* ≡ƒÄí Spin Trigger */}
      <motion.button
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setShowSpin(true)}
        className="flex items-center gap-2 px-4 py-2.5 rounded-2xl bg-[#C9A84C]/10 border border-[#C9A84C]/20 hover:bg-[#C9A84C]/20 transition-all group"
        title="Lucky Spin"
      >
        <div className="text-[#C9A84C] group-hover:rotate-45 transition-transform duration-500">
          <SpinIcon />
        </div>
        <span className="text-[10px] font-black uppercase tracking-widest text-[#C9A84C]">Spin</span>
      </motion.button>

      {/* ≡ƒÅ╖∩╕Å Coupons Trigger */}
      <motion.button
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setShowCoupons(true)}
        className="flex items-center gap-2 px-4 py-2.5 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all group"
        title="My Coupons"
      >
        <div className="text-secondary-text group-hover:text-white transition-colors">
          <CouponIcon />
        </div>
        <span className="text-[10px] font-black uppercase tracking-widest text-secondary-text group-hover:text-white transition-colors">Rewards</span>
      </motion.button>

      {/* ΓöÇΓöÇΓöÇ Modals ΓöÇΓöÇΓöÇ */}
      <AnimatePresence>
        {showSpin && (
          <ModalContent type="spin" onClose={() => setShowSpin(false)}>
            <div className="flex flex-col items-center">
              <span className="text-[10px] font-black uppercase tracking-[0.4em] text-[#C9A84C] mb-8">Daily Luck</span>
              <SpinWheel onWin={(p) => { onWin(p); setTimeout(() => setShowSpin(false), 2500); }} />
            </div>
          </ModalContent>
        )}

        {showCoupons && (
          <ModalContent type="coupons" onClose={() => setShowCoupons(false)}>
             <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-[0.4em] text-secondary-text mb-6">Gourmet Pass</span>
              <h2 className="text-2xl font-black text-white mb-8">Active Rewards</h2>
              <CouponSection />
            </div>
          </ModalContent>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";
import { useState, useEffect } from 'react';
import Image, { ImageProps } from 'next/image';

const FALLBACK_IMAGE = "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?q=80&w=800"; 

export default function SafeImage(props: ImageProps) {
  const [imgSrc, setImgSrc] = useState(props.src);

  useEffect(() => {
    setImgSrc(props.src);
  }, [props.src]);

  const { fill, alt, className, style, ...rest } = props;

  // Handle Next.js 'fill' prop via CSS
  const containerStyle: React.CSSProperties = fill 
    ? { position: 'absolute', height: '100%', width: '100%', left: 0, top: 0, right: 0, bottom: 0, objectFit: 'cover' }
    : {};

  const mergedStyle = { ...containerStyle, ...style };

  return (
    <img
      src={(imgSrc as string) || FALLBACK_IMAGE}
      alt={alt || 'Image'}
      style={mergedStyle}
      onError={() => {
        if (imgSrc !== FALLBACK_IMAGE) setImgSrc(FALLBACK_IMAGE);
      }}
      className={className}
    />
  );
}
